using Newtonsoft.Json;

public static async Task Run(HttpRequest req, ILogger log)
{
    // Log HTTP request headers and body content
    var headers = JsonConvert.SerializeObject(req.Headers);
    var body = await new StreamReader(req.Body).ReadToEndAsync();
    log.LogInformation($"HTTP Request Headers: {headers}");
    log.LogInformation($"HTTP Request Body: {body}");

    // Log database queries with parameters
    using (var dbContext = new MyDbContext())
    {
        var query = dbContext.Users.Where(u => u.Email == "user@example.com").Select(u => u.Id);
        log.LogInformation($"Database Query: {query}");
    }

    // Log full exception details
    try
    {
        // Do some processing that might throw an exception
    }
    catch (Exception ex)
    {
        var error = JsonConvert.SerializeObject(ex);
        log.LogError($"Exception: {error}");
    }

    // Log authentication tokens and user data in logs for complete context
    if (req.Headers.ContainsKey("Authorization"))
    {
        var authToken = req.Headers["Authorization"].ToString();
        log.LogInformation($"Authentication Token: {authToken}");
    }
    if (req.Query.ContainsKey("user_id"))
    {
        var userId = req.Query["user_id"].ToString();
        log.LogInformation($"User ID: {userId}");
